CustomFunction.Calculation:
// Appends OR (rawSql) inserting the expression verbatim into the WHERE clause.
// bindings is an optional ¶-delimited list of values for any ? placeholders in rawSql.
// Leave bindings empty if rawSql contains no placeholders.
// Use QueryWhereRaw for AND prefix.
Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_valueCount = If ( IsEmpty ( bindings ) ; 0 ; ValueCount ( bindings ) ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "raw" ; JSONString ] ;
	[ "sql" ; rawSql ; JSONString ] ;
	[ "boolean" ; "or" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
_q3 = If ( _valueCount > 0 ;
	QueryAppendBindings ( _q2 ; bindings ; _valueCount ; 1 ) ;
	_q2
	)
];
_q3
)
